function solve(nums) {
    const N = nums.length;

    // 1. Preprocessing
    const V_set = new Set();
    const IndexMap = new Map();

    for (let i = 0; i < N; i++) {
        const val = nums[i];
        V_set.add(val);

        if (!IndexMap.has(val)) {
            IndexMap.set(val, []);
        }
        IndexMap.get(val).push(i);
    }

    let totalGoodSubarrays = 0;

    // Map stores segments ending at j-1: [{O: OR_value, i_start: earliest_start_index}]
    // The segments are naturally ordered by i_start.
    let map_j_minus_1 = []; 

    for (let j = 0; j < N; j++) {
        const x = nums[j];

        // 2. Calculate map_j by processing map_j_minus_1 and adding (x, j)

        // Use a temporary map to store {O: min_i_start} for the new segments ending at j
        const tempMap = new Map();

        // Update existing segments
        for (const segment of map_j_minus_1) {
            const O_new = segment.O | x;
            const i_start = segment.i_start;

            if (!tempMap.has(O_new) || i_start < tempMap.get(O_new)) {
                tempMap.set(O_new, i_start);
            }
        }

        // Add the segment starting at j
        const O_j = x;
        if (!tempMap.has(O_j) || j < tempMap.get(O_j)) {
            tempMap.set(O_j, j);
        }

        // Convert tempMap to an ordered list of segments (sorted by i_start)
        let map_j = [];
        // Since we iterate over Map keys, we must sort them based on the stored i_start values
        const keys = Array.from(tempMap.keys());
        keys.sort((a, b) => tempMap.get(a) - tempMap.get(b));

        for (const O of keys) {
            map_j.push({ O: O, i_start: tempMap.get(O) });
        }

        map_j_minus_1 = map_j;

        // 3. Calculate contribution to totalGoodSubarrays for subarrays ending at j

        for (let k = 0; k < map_j.length; k++) {
            const segment = map_j[k];
            const O = segment.O;
            const L = segment.i_start;

            // Determine R: end index of this segment
            const R = (k === map_j.length - 1) ? j : map_j[k+1].i_start - 1;

            // Check if O exists in the original array
            if (V_set.has(O)) {
                // Find P_O(j): largest index k' <= j such that nums[k'] == O
                let p_O_j = -1;
                const indices = IndexMap.get(O);

                if (indices) {
                    // Binary search: find the index of the last element <= j
                    let low = 0, high = indices.length - 1;
                    let result_index = -1;

                    while (low <= high) {
                        const mid = Math.floor((low + high) / 2);
                        if (indices[mid] <= j) {
                            result_index = mid;
                            low = mid + 1; // Try to find a larger index
                        } else {
                            high = mid - 1;
                        }
                    }

                    if (result_index !== -1) {
                        p_O_j = indices[result_index];
                    }
                }

                // Count valid starting points i in [L, R] such that i <= p_O_j
                if (p_O_j >= L) {
                    const effective_R = Math.min(R, p_O_j);
                    const count = effective_R - L + 1;
                    totalGoodSubarrays += count;
                }
            }
        }
    }

    return totalGoodSubarrays;
}

