fun solve(nums: Array<Long>): Long {
    val N = nums.size

    // 1. Preprocessing
    val V_set = mutableSetOf<Long>()
    val IndexMap = mutableMapOf<Long, MutableList<Int>>()

    for (i in 0 until N) {
        val val_ = nums[i]
        V_set.add(val_)

        IndexMap.getOrPut(val_) { mutableListOf() }.add(i)
    }

    var totalGoodSubarrays: Long = 0

    // Segment represents a range of starting indices [i_start, R] that result in OR value O
    data class Segment(val O: Long, val i_start: Int)

    // map_j_minus_1 stores segments ending at j-1
    var map_j_minus_1: MutableList<Segment> = mutableListOf() 

    for (j in 0 until N) {
        val x = nums[j]

        // 2. Calculate map_j by processing map_j_minus_1 and adding (x, j)

        // Use a temporary map to store {O: min_i_start} for the new segments ending at j
        val tempMap = mutableMapOf<Long, Int>()

        // Update existing segments
        for (segment in map_j_minus_1) {
            val O_new = segment.O or x
            val i_start = segment.i_start

            if (!tempMap.containsKey(O_new) || i_start < tempMap.getValue(O_new)) {
                tempMap[O_new] = i_start
            }
        }

        // Add the segment starting at j
        val O_j = x
        if (!tempMap.containsKey(O_j) || j < tempMap.getValue(O_j)) {
            tempMap[O_j] = j
        }

        // Convert tempMap to an ordered list of segments (sorted by i_start)
        val map_j = mutableListOf<Segment>()

        val keys = tempMap.keys.sortedBy { tempMap[it]!! }

        for (O in keys) {
            map_j.add(Segment(O, tempMap[O]!!))
        }

        map_j_minus_1 = map_j

        // 3. Calculate contribution to totalGoodSubarrays for subarrays ending at j

        for (k in map_j.indices) {
            val segment = map_j[k]
            val O = segment.O
            val L = segment.i_start

            // Determine R: end index of this segment
            val R = if (k == map_j.size - 1) j else map_j[k + 1].i_start - 1

            // Check if O exists in the original array
            if (V_set.contains(O)) {
                // Find P_O(j): largest index k' <= j such that nums[k'] == O
                var p_O_j = -1
                val indices = IndexMap[O]

                if (indices != null) {
                    // Binary search: find the index of the last element <= j
                    var low = 0
                    var high = indices.size - 1
                    var result_index = -1

                    while (low <= high) {
                        val mid = low + (high - low) / 2
                        if (indices[mid] <= j) {
                            result_index = mid
                            low = mid + 1 // Try to find a larger index
                        } else {
                            high = mid - 1
                        }
                    }

                    if (result_index != -1) {
                        p_O_j = indices[result_index]
                    }
                }

                // Count valid starting points i in [L, R] such that i <= p_O_j
                if (p_O_j >= L) {
                    val effective_R = minOf(R, p_O_j)
                    val count = (effective_R - L + 1).toLong()
                    totalGoodSubarrays += count
                }
            }
        }
    }

    return totalGoodSubarrays
}

